// ── Math Problem Generator (class-based difficulty) ──
export const generateMathProblem = (classLevel: number) => {
  const level = Math.min(classLevel, 8);
  let a: number, b: number, answer: number, question: string;

  if (level <= 2) {
    const isAdd = Math.random() > 0.4;
    a = Math.floor(Math.random() * 15) + 1;
    b = Math.floor(Math.random() * (isAdd ? 10 : a)) + 1;
    if (isAdd) { answer = a + b; question = `${a} + ${b}`; }
    else { answer = a - b; question = `${a} - ${b}`; }
  } else if (level <= 4) {
    const ops = ["+", "-", "×", "÷"];
    const op = ops[Math.floor(Math.random() * 4)];
    if (op === "+") { a = Math.floor(Math.random() * 50) + 1; b = Math.floor(Math.random() * 50) + 1; answer = a + b; question = `${a} + ${b}`; }
    else if (op === "-") { a = Math.floor(Math.random() * 50) + 10; b = Math.floor(Math.random() * a) + 1; answer = a - b; question = `${a} - ${b}`; }
    else if (op === "×") { a = Math.floor(Math.random() * 10) + 2; b = Math.floor(Math.random() * 10) + 2; answer = a * b; question = `${a} × ${b}`; }
    else { b = Math.floor(Math.random() * 9) + 2; a = b * (Math.floor(Math.random() * 10) + 1); answer = a / b; question = `${a} ÷ ${b}`; }
  } else if (level <= 6) {
    const ops = ["+", "-", "×", "÷", "mixed"];
    const op = ops[Math.floor(Math.random() * 5)];
    if (op === "+") { a = Math.floor(Math.random() * 200) + 50; b = Math.floor(Math.random() * 200) + 50; answer = a + b; question = `${a} + ${b}`; }
    else if (op === "-") { a = Math.floor(Math.random() * 300) + 100; b = Math.floor(Math.random() * a) + 1; answer = a - b; question = `${a} - ${b}`; }
    else if (op === "×") { a = Math.floor(Math.random() * 12) + 2; b = Math.floor(Math.random() * 15) + 2; answer = a * b; question = `${a} × ${b}`; }
    else if (op === "÷") { b = Math.floor(Math.random() * 12) + 2; a = b * (Math.floor(Math.random() * 12) + 2); answer = a / b; question = `${a} ÷ ${b}`; }
    else { a = Math.floor(Math.random() * 10) + 2; b = Math.floor(Math.random() * 5) + 1; const c = Math.floor(Math.random() * 10) + 1; answer = a * b + c; question = `${a} × ${b} + ${c}`; }
  } else {
    const types = ["square", "cube", "large_mult", "large_div", "mixed"];
    const type = types[Math.floor(Math.random() * 5)];
    if (type === "square") { a = Math.floor(Math.random() * 15) + 2; answer = a * a; question = `${a}²`; }
    else if (type === "cube") { a = Math.floor(Math.random() * 8) + 2; answer = a * a * a; question = `${a}³`; }
    else if (type === "large_mult") { a = Math.floor(Math.random() * 20) + 10; b = Math.floor(Math.random() * 15) + 5; answer = a * b; question = `${a} × ${b}`; }
    else if (type === "large_div") { b = Math.floor(Math.random() * 15) + 2; a = b * (Math.floor(Math.random() * 20) + 5); answer = a / b; question = `${a} ÷ ${b}`; }
    else { a = Math.floor(Math.random() * 12) + 2; b = Math.floor(Math.random() * 12) + 2; const c = Math.floor(Math.random() * 10) + 1; answer = a * b - c; question = `${a} × ${b} - ${c}`; }
  }

  question += " = ?";
  const wrongSet = new Set<number>();
  while (wrongSet.size < 3) {
    const offset = Math.floor(Math.random() * Math.max(10, Math.abs(answer) * 0.3)) + 1;
    const wrong = Math.random() > 0.5 ? answer + offset : Math.max(0, answer - offset);
    if (wrong !== answer) wrongSet.add(wrong);
  }
  const options = shuffle([answer, ...wrongSet].map(String));
  return { question, answer: String(answer), options };
};

