export const shuffle = <T,>(arr: T[]): T[] => [...arr].sort(() => Math.random() - 0.5);

export const filterByClass = <T extends { classRange: [number, number] }>(items: T[], classLevel: number): T[] => {
  return items.filter(item => classLevel >= item.classRange[0] && classLevel <= item.classRange[1]);
};

export const getClassLabel = (level: number): string => {
  if (level <= 2) return "Beginner";
  if (level <= 4) return "Intermediate";
  if (level <= 6) return "Advanced";
  return "Expert";
};

export const getClassLabelTamil = (level: number): string => {
  if (level <= 2) return "தொடக்கம்";
  if (level <= 4) return "இடைநிலை";
  if (level <= 6) return "மேம்பட்ட";
  return "நிபுணர்";
};
